import React from 'react';
import { Button } from '@linm-soft-org/linm-web-common-components';

export interface ListSearchRefreshButtonsProps {
  testIdPrefix: string;
  onSearch: () => void;
  onRefresh: () => void;
  /** False when list has no text search (date/status only). */
  showSearch?: boolean;
  /** Hide refresh icon (toolbar already has Làm mới). */
  hideRefresh?: boolean;
}

export const ListSearchRefreshButtons: React.FC<ListSearchRefreshButtonsProps> = ({
  testIdPrefix,
  onSearch,
  onRefresh,
  showSearch = true,
  hideRefresh = false,
}) => (
  <>
    {showSearch && (
      <Button
        variant="secondary"
        onClick={onSearch}
        aria-label="Tìm kiếm"
        data-testid={`${testIdPrefix}-search-btn`}
      >
        <i className="fas fa-search" />
      </Button>
    )}
    {!hideRefresh && (
    <Button
      variant="secondary"
      onClick={onRefresh}
      aria-label="Làm mới"
      data-testid={`${testIdPrefix}-refresh-btn`}
    >
      <i className="fas fa-sync" />
    </Button>
    )}
  </>
);

export default ListSearchRefreshButtons;
